// ── Validate & Normalize Incoming Log Payload ───────────────
const VALID_LEVELS = ['DEBUG', 'INFO', 'WARN', 'ERROR', 'FATAL'];

const input = $input.first().json;
const body = input.body ?? input;
const headers = input.headers ?? {};

// ── Required field check ─────────────────────────────────────
if (!body.message || typeof body.message !== 'string' || body.message.trim() === '') {
  throw new Error('Validation failed: `message` is required and must be a non-empty string.');
}

// ── Normalize level ──────────────────────────────────────────
const rawLevel = (body.level ?? 'INFO').toString().toUpperCase().trim();
const level = VALID_LEVELS.includes(rawLevel) ? rawLevel : 'INFO';

// ── Normalize client IP (first forwarded hop only) ───────────
const forwardedHeader =
  headers['x-forwarded-for']
  ?? headers['X-Forwarded-For']
  ?? headers['x-real-ip']
  ?? headers['X-Real-IP']
  ?? null;

const forwardedValue = Array.isArray(forwardedHeader) ? forwardedHeader[0] : forwardedHeader;
let ipAddress = null;

if (typeof forwardedValue === 'string' && forwardedValue.trim() !== '') {
  const firstHop = forwardedValue.split(',')[0].trim();
  const ipv4WithPort = firstHop.match(/^(\d{1,3}(?:\.\d{1,3}){3}):\d+$/);
  const bracketedIpv6 = firstHop.match(/^\[([0-9a-fA-F:]+)\](?::\d+)?$/);

  if (ipv4WithPort) {
    ipAddress = ipv4WithPort[1];
  } else if (bracketedIpv6) {
    ipAddress = bracketedIpv6[1];
  } else {
    ipAddress = firstHop;
  }
}

// ── Extract execution context injected by n8n ────────────────
const execId   = $execution?.id   ?? null;
const wfId     = $workflow?.id    ?? null;
const wfName   = $workflow?.name  ?? null;

// ── Build clean log entry ────────────────────────────────────
const logEntry = {
  level,
  message:       body.message.trim().substring(0, 5000),
  source:        (body.source ?? 'n8n').toString().substring(0, 100),
  workflow_id:   wfId,
  workflow_name: wfName,
  execution_id:  execId,
  metadata:      (body.metadata && typeof body.metadata === 'object' && !Array.isArray(body.metadata)) ? body.metadata : {},
  error_code:    body.error_code  ?? null,
  error_stack:   body.error_stack ?? null,
  request_id:    body.request_id  ?? null,
  user_id:       body.user_id     ?? null,
  ip_address:    ipAddress
};

return [{ json: logEntry }];

// ── Build Slack / Email alert for FATAL logs ────────────────
const log = $input.first().json;

const alertPayload = {
  title:    '🚨 FATAL LOG ALERT',
  text:     `*${log.source}* reported a FATAL error`,
  fields: [
    { label: 'Message',    value: log.message },
    { label: 'Workflow',   value: log.workflow_name ?? 'N/A' },
    { label: 'Execution',  value: log.execution_id  ?? 'N/A' },
    { label: 'Error Code', value: log.error_code    ?? 'N/A' },
    { label: 'User',       value: log.user_id       ?? 'N/A' },
    { label: 'Stack',      value: (log.error_stack ?? '').substring(0, 500) }
  ],
  timestamp: new Date().toISOString()
};

return [{
  json: {
    ...log,
    alert_payload: alertPayload
  }
}];

// Return success payload to the parent workflow
const inserted = $input.first().json;

return [{
  json: {
    success: true,
    log_id: inserted.id,
    level: inserted.level,
    saved_at: inserted.created_at
  }
}];

// ── Global error handler for workflow error output ───────────
const payload = $input.first().json ?? {};
const nestedError = payload.error ?? payload.execution?.error ?? null;

const errorMessage =
  nestedError?.message
  ?? payload.message
  ?? (typeof nestedError === 'string' ? nestedError : null)
  ?? 'Unknown error occurred';

console.error('[Logger Workflow Error]', errorMessage);

return [{
  json: {
    success: false,
    error: errorMessage,
    timestamp: new Date().toISOString()
  }
}];
